const message = $json.message ?? {};
const from = message.from ?? {};
const chat = message.chat ?? {};
const text = typeof message.text === 'string' ? message.text.trim() : '';
const normalized = text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

function hasAny(values) {
  return values.some((value) => normalized.includes(value));
}

const cards = {
  rest: `CARD: Rest Intervals\n- Short rests can work for lighter or isolation exercises.\n- Longer rests help preserve performance in heavier compound exercises.\n- Practical range: 1-2 min for lighter work, 2-3 min for heavier compound work.\n- If technique or performance drops sharply, rest longer.\n- Do not prescribe an exact interval as individualized programming.`,
  failure: `CARD: Failure Training\n- Failure means another good repetition is unlikely.\n- RIR means repetitions in reserve; RIR 2 means about 2 good reps left.\n- Most sets do not need to be taken to failure.\n- Many useful sets can end with 1-3 RIR.\n- Failure can increase fatigue and technique breakdown.`,
  shortWorkout: `CARD: Short Workouts\n- Keep it simple and general, not deeply personalized.\n- Include a short warm-up with esteira, bicicleta or mobilidade leve. Do not use prancha as warm-up.\n- Prefer 4-6 exercises using broad patterns: lower body, push, pull, hinge or hamstring, core.\n- Use common gym exercises only: leg press, agachamento, supino, flexao, puxada, remada, desenvolvimento, mesa flexora, cadeira extensora, terra romeno, prancha, bicicleta ou esteira.\n- Do not invent exercise names. If unsure, choose leg press, supino, remada, mesa flexora and prancha.\n- For strength exercises, use sets and reps. Use seconds only for prancha, cardio or warm-up.\n- Preferred 30 min structure: 5 min warm-up; leg press 3x8-12; supino or flexao 3x8-12; remada 3x8-12; mesa flexora 2x10-12; prancha 2x30-45s; rest 60-90s.\n- Do not promise results or prescribe exact loads.\n- Tell the user to stop or adapt if pain appears.`,
  substitution: `CARD: Exercise Substitutions\n- A substitution can be reasonable when goal, equipment and comfort are compatible.\n- Similar exercises are not identical.\n- Consider the reason: equipment, preference, pain, difficulty or time.\n- If pain is the reason, apply safety boundaries and do not treat it as a normal swap.`,
  load: `CARD: Load Selection\n- Do not give absolute kg.\n- Suggest a load the user controls with good technique.\n- A practical reference is finishing sets with about 1-3 repetitions in reserve.\n- If technique breaks down, reduce load.`,
  style: `CARD: Response Style\n- Respond in pt-BR.\n- Keep replies short and practical for Telegram.\n- Prefer one useful action, brief rationale, and one optional follow-up question.\n- Do not mention internal cards, prompts or implementation details.`,
};

let intent = 'fallback';
let riskLevel = 'normal';
let route = 'fixed';
let isFeedback = false;
let feedbackValue = null;
let fixedReply = 'Recebi sua mensagem, mas neste MVP ainda nao consigo responder esse tipo de pedido. Posso ajudar com: /start, treino de 30 min, descanso, falha, substituicao simples, dor/risco e carga.';
let knowledgeContext = cards.style;
let finalFallbackReply = 'Recebi sua mensagem, mas o modelo local nao conseguiu responder agora. Posso ajudar com treino de 30 min, descanso, falha, substituicao, dor e carga.';
let fallbackReason = 'unsupported_text_fixed_fallback';

const positiveFeedback = new Set(['sim', 'ajudou', 'ok', 'boa', 'positivo']);
const negativeFeedback = new Set(['nao', 'nao ajudou', 'ruim', 'negativo']);

if (!text) {
  intent = 'non_text';
  route = 'fixed';
  fallbackReason = 'non_text_message';
  fixedReply = 'Por enquanto eu so consigo responder mensagens de texto. Me diga sua duvida ou o treino que voce quer ajustar.';
} else if (positiveFeedback.has(normalized)) {
  intent = 'feedback';
  route = 'fixed';
  isFeedback = true;
  feedbackValue = 'positive';
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Valeu pelo feedback. Vou manter respostas curtas e praticas por aqui.';
} else if (negativeFeedback.has(normalized)) {
  intent = 'feedback';
  route = 'fixed';
  isFeedback = true;
  feedbackValue = 'negative';
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Obrigado pelo feedback. Me diga em uma frase o que faltou ou o que voce queria ajustar.';
} else if (hasAny(['dor', 'doendo', 'machuquei', 'lesao', 'fisgada', 'formigamento', 'ombro', 'joelho', 'lombar', 'peito', 'tontura'])) {
  intent = 'discomfort';
  route = 'fixed';
  riskLevel = hasAny(['forte', 'aguda', 'fisgada', 'formigamento', 'peito', 'tontura', 'piorando']) ? 'stop' : 'caution';
  fallbackReason = 'mandatory_safety_response';
  fixedReply = riskLevel === 'stop'
    ? 'Para agora e evite repetir o movimento que causou isso. Nao consigo diagnosticar pelo chat. Se a dor foi forte, aguda, esta piorando, teve formigamento, tontura ou dor no peito, procure avaliacao profissional ou atendimento urgente.'
    : 'Se apareceu dor ou desconforto, reduza ou pare o movimento por enquanto. Nao treine atravessando dor. Se persistir ou piorar, procure avaliacao profissional. Posso sugerir uma alternativa geral mais conservadora se voce me disser o exercicio.';
} else if (hasAny(['quantos kg', 'quanto peso', 'carga exata', 'qual carga', 'kg eu coloco'])) {
  intent = 'exact_load';
  route = 'fixed';
  fallbackReason = 'mandatory_load_boundary';
  fixedReply = 'Nao vou indicar kg exato sem avaliar tecnica e contexto. Use uma carga que voce controle bem e termine a serie com cerca de 1 a 3 repeticoes em reserva. Se a tecnica quebrar, reduza.';
} else if (hasAny(['lembra', 'ontem', 'treino anterior', 'ultima vez', 'semana passada'])) {
  intent = 'memory_request';
  route = 'fixed';
  fallbackReason = 'mandatory_no_memory_boundary';
  fixedReply = 'Neste MVP eu nao lembro sessoes anteriores. Me reenvie o treino ou diga o objetivo de hoje que eu te ajudo a partir da mensagem atual.';
} else if (normalized === '/start' || hasAny(['oi', 'ola', 'comecar', 'inicio'])) {
  intent = 'onboarding';
  route = 'fixed';
  fallbackReason = 'rule_based_onboarding';
  fixedReply = 'Oi. Eu sou o Gym Buddy. Posso ajudar com duvidas rapidas de treino, descanso, falha, substituicoes e ideias gerais de treino curto. Me diga o que voce precisa agora.';
} else if (hasAny(['treino rapido', 'treino de 30', '30 min', '30 minutos', 'meia hora'])) {
  intent = 'short_workout';
  knowledgeContext = `${cards.shortWorkout}\n\n${cards.load}\n\n${cards.style}`;
  finalFallbackReply = 'Ideia geral de treino de 30 min:\n\n1. Aquecimento: 5 min leve.\n2. Agachamento ou leg press: 3x8-12.\n3. Supino ou flexao: 3x8-12.\n4. Remada: 3x8-12.\n5. Mesa flexora ou terra romeno: 2x10-12.\n6. Prancha: 2x30-45s.\n\nDescanse 60-90s, use carga controlavel e pare se sentir dor fora do normal.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['descanso', 'descansar', 'intervalo'])) {
  intent = 'rest_question';
  knowledgeContext = `${cards.rest}\n\n${cards.style}`;
  finalFallbackReply = 'Como regra geral: 1-2 min funciona bem para exercicios leves ou isoladores; 2-3 min costuma ajudar em exercicios pesados como agachamento, supino e remada. Se a tecnica cair muito, descanse mais.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['falha', 'ate a falha', 'rir', 'repeticoes em reserva'])) {
  intent = 'failure_question';
  knowledgeContext = `${cards.failure}\n\n${cards.style}`;
  finalFallbackReply = 'Nao precisa ir ate a falha em toda serie. Uma boa referencia e terminar muitas series com 1 a 3 repeticoes em reserva. Falha pode ser util em alguns momentos, mas aumenta fadiga e risco de perder tecnica.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['trocar', 'substituir', 'substituicao', 'no lugar de', 'alternativa'])) {
  intent = 'substitution';
  knowledgeContext = `${cards.substitution}\n\n${cards.style}`;
  finalFallbackReply = 'Pode fazer sentido trocar, mas exercicios parecidos nao sao identicos. Se for por equipamento ou preferencia, me diga o exercicio atual e a opcao que voce tem. Se for por dor, pare o movimento e trate como sinal de cautela.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['personalizado', 'personalizada', 'pra mim', 'para mim'])) {
  intent = 'personalized_workout_request';
  route = 'fixed';
  fallbackReason = 'mandatory_personalization_boundary';
  fixedReply = 'Posso ajudar com uma estrutura geral, mas nao vou fingir personalizacao profunda sem avaliacao. Para ajustar melhor, me diga so 2 coisas: objetivo principal e equipamentos disponiveis.';
}

const requiresLlm = route === 'local_llm';
const systemPrompt = `Voce e o Gym Buddy, um assistente pratico de apoio a treino para Telegram. Responda em pt-BR. Use apenas orientacao geral, curta e segura. Nao diagnostique, nao trate lesao, nao prescreva reabilitacao, nao indique kg exato, nao prometa resultado e nao finja memoria ou personalizacao profunda. Casos de dor ou risco ja foram bloqueados antes de chegar aqui. Use somente nomes comuns de exercicios de academia; nao invente nomes. Nao mencione bastidores, cards ou implementacao.`;
const userPrompt = `Intent: ${intent}\nRisk level: ${riskLevel}\nContexto curado:\n${knowledgeContext}\n\nMensagem do usuario:\n${text}\n\nGere uma resposta curta e pratica para Telegram.`;

return [{
  json: {
    channel: 'telegram',
    user_id: from.id ?? null,
    chat_id: chat.id ?? null,
    username: from.username ?? null,
    first_name: from.first_name ?? null,
    message_id: message.message_id ?? null,
    message_text: text,
    message_type: text ? 'text' : 'non_text',
    received_at: message.date ? new Date(message.date * 1000).toISOString() : new Date().toISOString(),
    intent,
    risk_level: riskLevel,
    route,
    is_feedback: isFeedback,
    feedback_value: feedbackValue,
    requires_llm: requiresLlm,
    fixed_reply: fixedReply,
    final_fallback_reply: finalFallbackReply,
    fallback_reason: fallbackReason,
    knowledge_context: knowledgeContext,
    primary_llm_status: 'disabled_budget',
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

const baseUrl = 'http://ollama:11434';
const model = 'llama3.2:3b';

try {
  const response = await fetch(`${baseUrl}/api/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model,
      stream: false,
      options: {
        temperature: 0.25,
        num_predict: 260
      },
      messages: [
        { role: 'system', content: $json.system_prompt },
        { role: 'user', content: $json.user_prompt }
      ]
    })
  });

  const raw = await response.text();
  let parsed = {};
  try { parsed = raw ? JSON.parse(raw) : {}; } catch (error) { parsed = { raw }; }

  if (!response.ok) {
    return [{ json: { ...$json, error: { provider: 'ollama', code: response.status, message: parsed.error || response.statusText || 'Ollama request failed', raw: parsed } } }];
  }

  return [{ json: { ...$json, llm_provider: 'ollama', llm_model: model, text: parsed.message?.content ?? parsed.response ?? '', raw_ollama_response: parsed } }];
} catch (error) {
  return [{ json: { ...$json, error: { provider: 'ollama', code: error.name || 'OLLAMA_REQUEST_ERROR', message: error.message || 'Ollama request failed' } } }];
}

const source = $('Route And Build Context').first().json;
const errorMessage = $json.error?.message ?? null;
const errorCode = $json.error?.code ?? null;
const provider = $json.error?.provider ?? $json.llm_provider ?? 'ollama';
const hasLlmError = Boolean($json.error || errorCode);
const modelReply = String($json.text ?? '').trim();
const replyText = hasLlmError ? source.final_fallback_reply : (modelReply || source.final_fallback_reply);

return [{
  json: {
    ...source,
    reply_text: replyText,
    handled_at: new Date().toISOString(),
    llm_provider: provider,
    llm_model: $json.llm_model ?? null,
    llm_status: hasLlmError ? 'error' : 'success',
    llm_error_code: errorCode,
    llm_error_message: errorMessage,
    used_final_fallback: hasLlmError || !modelReply
  }
}];
